func TestDecodeReliableCommand(t *testing.T) {
	payload := []byte{0x79, 0x9e, 0x0, 0x1, 0x0, 0x0, 0x15, 0x5c, 0x7c, 0x11, 0x66, 0xbd, 0x6, 0x0, 0x1, 0x4, 0x0, 0x0, 0x0, 0x41, 0x0, 0x0, 0x0, 0x1b, 0xf3, 0x2, 0x1, 0x6, 0x0, 0xa, 0xca, 0xd0, 0xa2, 0xb9, 0xa1, 0xf5, 0xce, 0xde, 0x11, 0x1, 0x45, 0x2, 0xbb, 0x8c, 0x7f, 0xc2, 0x60, 0xf3, 0xb6, 0xc3, 0x2, 0x5, 0xab, 0x77, 0xa2, 0x42, 0x3, 0x45, 0x2, 0x52, 0xfc, 0x70, 0xc2, 0x82, 0xab, 0xb6, 0xc3, 0x4, 0x5, 0xd7, 0xa3, 0x32, 0x41, 0xfd, 0x4, 0x16, 0x0}

	parser := photon.NewV18()

	sess := photon.Session[v18.Parameter]{}

	err := parser.ParsePacketInto(payload, &sess)
	if err != nil {
		t.Fatalf("can't parse due to: %v", err)
	}

	if len(sess.Commands) != 1 {
		t.Fatalf("session must have at least one command got: %v", len(sess.Commands))
	}

	if len(sess.Commands[0].ReliablePayload.Parameters) != 6 {
		t.Fatalf("command must have at least 6 parameters got: %v", len(sess.Commands[0].ReliablePayload.Parameters))
	}
}

func TestAcknowledgeChainedWithSendReliable(t *testing.T) {

	payload := []byte{0x79, 0x9e, 0x0, 0x3, 0x0, 0x0, 0x4, 0xef, 0x7c, 0x11, 0x66, 0xbd, 0x1, 0x0, 0x0, 0x4, 0x0, 0x0, 0x0, 0x14, 0x0, 0x0, 0x0, 0x0, 0x0, 0x0, 0x0, 0x62, 0xad, 0xb8, 0x93, 0xbc, 0x6, 0x0, 0x1, 0x4, 0x0, 0x0, 0x0, 0x68, 0x0, 0x0, 0x0, 0x5, 0xf3, 0x2, 0x1, 0xc, 0x0, 0x7, 0x8, 0x41, 0x70, 0x70, 0x6c, 0x65, 0x20, 0x4d, 0x34, 0x1, 0x7, 0x8, 0x41, 0x70, 0x70, 0x6c, 0x65, 0x20, 0x4d, 0x34, 0x2, 0x7, 0xf, 0x4d, 0x61, 0x63, 0x20, 0x4f, 0x53, 0x20, 0x58, 0x20, 0x32, 0x36, 0x2e, 0x33, 0x2e, 0x30, 0x3, 0xd, 0x60, 0x9, 0x4, 0xd, 0x5c, 0x2f, 0x5, 0xd, 0x0, 0x40, 0x6, 0x7, 0x5, 0x45, 0x4e, 0x2d, 0x55, 0x53, 0x7, 0x7, 0x6, 0x43, 0x75, 0x73, 0x74, 0x6f, 0x6d, 0x8, 0x7, 0x5, 0x4d, 0x65, 0x74, 0x61, 0x6c, 0x9, 0xd, 0xbf, 0xd, 0xb, 0x10, 0x1, 0xfd, 0x4, 0x2c, 0x1, 0x6, 0x0, 0x1, 0x4, 0x0, 0x0, 0x0, 0x17, 0x0, 0x0, 0x0, 0x6, 0xf3, 0x2, 0x1, 0x2, 0x0, 0x47, 0x0, 0xfd, 0x4, 0xff, 0x1}

	parser := photon.NewV18()

	sess := photon.Session[v18.Parameter]{}

	err := parser.ParsePacketInto(payload, &sess)
	if err != nil {
		t.Fatalf("can't parse due to: %v", err)
	}

	if len(sess.Commands) != 3 {
		t.Fatalf("session must have at least 2 commands got: %v", len(sess.Commands))
	}

	if sess.Commands[0].Type != types.AcknowledgeCommand {
		t.Fatalf("command must be an acknowledge command got: %v", sess.Commands[0].Type)
	}

	if sess.Commands[0].AcknowledgePayload.AckReliableSequenceNumber == 0 {
		t.Fatalf("acknowledge payload must have a reliable sequence number of 0 got: %v", sess.Commands[0].AcknowledgePayload.AckReliableSequenceNumber)
	}

	if sess.Commands[0].AcknowledgePayload.AckSentTime == 0 {
		t.Fatalf("acknowledge payload must have a sent time of 0 got: %v", sess.Commands[0].AcknowledgePayload.AckSentTime)
	}

	if sess.Commands[1].Type != types.SendReliableCommand {
		t.Fatalf("command must be a send reliable command got: %v", sess.Commands[1].Type)
	}

	if sess.Commands[1].ReliablePayload.ParameterCount == 0 {
		t.Fatalf("reliable payload must have more than 0 parameter count got: %v", sess.Commands[1].ReliablePayload.ParameterCount)
	}

	if sess.Commands[2].Type != types.SendReliableCommand {
		t.Fatalf("command must be a send reliable command got: %v", sess.Commands[2].Type)
	}

	if sess.Commands[2].ReliablePayload.ParameterCount == 0 {
		t.Fatalf("reliable payload must have more than 0 parameter count got: %v", sess.Commands[1].ReliablePayload.ParameterCount)
	}

}

func TestAcknowledgeChainedWithPing(t *testing.T) {

	payload := []byte{0x79, 0x9e, 0x0, 0x2, 0x0, 0x0, 0x49, 0x1e, 0x7c, 0x11, 0x66, 0xbd, 0x1, 0xff, 0x0, 0x4, 0x0, 0x0, 0x0, 0x14, 0x0, 0x0, 0x0, 0x0, 0x0, 0x0, 0x0, 0x8, 0xad, 0xb8, 0xd9, 0x60, 0x5, 0xff, 0x1, 0x4, 0x0, 0x0, 0x0, 0xc, 0x0, 0x0, 0x0, 0x9}
	parser := photon.NewV18()

	sess := photon.Session[v18.Parameter]{}

	err := parser.ParsePacketInto(payload, &sess)
	if err != nil {
		t.Fatalf("can't parse due to: %v", err)
	}

	if len(sess.Commands) != 2 {
		t.Fatalf("session must have at least 2 commands got: %v", len(sess.Commands))
	}

	if sess.Commands[0].AcknowledgePayload.AckReliableSequenceNumber == 0 {
		t.Fatalf("acknowledge payload must have a reliable sequence number of 0 got: %v", sess.Commands[0].AcknowledgePayload.AckReliableSequenceNumber)
	}

	if sess.Commands[0].AcknowledgePayload.AckSentTime == 0 {
		t.Fatalf("acknowledge payload must have a sent time of 0 got: %v", sess.Commands[0].AcknowledgePayload.AckSentTime)
	}

	if sess.Commands[1].Type != types.PingCommand {
		t.Fatalf("command must be a ping command got: %v", sess.Commands[1].Type)
	}

}

